import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api/axios';
import Navbar from '../components/Navbar';
import UptimeBadge from '../components/UptimeBadge';
import LatencyChart from '../components/LatencyChart';
import { formatTime } from '../utils/time';

export default function EndpointDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [endpoint, setEndpoint] = useState(null);
  const [history, setHistory]   = useState([]);

  useEffect(() => {
    api.get('/api/endpoints').then(({ data }) => setEndpoint(data.find(e => e.id === id)));
    api.get(`/api/endpoints/${id}/history?hours=24`).then(({ data }) => setHistory(data));
  }, [id]);

  const latest     = history[history.length - 1];
  const upCount    = history.filter(p => p.status === 'UP').length;
  const uptime     = history.length ? ((upCount / history.length) * 100).toFixed(2) : 'N/A';
  const validLat   = history.filter(p => p.latencyMs >= 0);
  const avgLatency = validLat.length
    ? Math.round(validLat.reduce((a, b) => a + b.latencyMs, 0) / validLat.length) : 0;

  const stats = [
    { label: '24h Uptime',   value: `${uptime}%`,        color: 'text-green-600 dark:text-gh-green-em' },
    { label: 'Avg Latency',  value: `${avgLatency}ms`,   color: 'text-brand-blue' },
    { label: 'Checks (24h)', value: `${history.length}`, color: 'text-gray-700 dark:text-gh-text' },
  ];

  const latencyCls = (ms) => {
    if (ms > 1000) return 'text-orange-500 dark:text-orange-400';
    if (ms > 500)  return 'text-yellow-600 dark:text-yellow-400';
    return 'text-green-600 dark:text-gh-green-em';
  };

  return (
    <div className="min-h-screen bg-[#f4f5f7] dark:bg-gh-canvas">
      <Navbar />
      <div className="max-w-4xl mx-auto px-4 py-5 space-y-4">
        <button onClick={() => navigate('/dashboard')} className="flex items-center gap-1.5 text-sm text-gray-500 dark:text-gh-muted hover:text-gray-900 dark:hover:text-gh-text transition-colors">
          ← Back to Dashboard
        </button>

        {endpoint && (
          <>
            {/* Header */}
            <div className="flex items-start justify-between bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border px-5 py-4">
              <div>
                <h1 className="text-lg font-bold text-gray-900 dark:text-gh-text">{endpoint.name || endpoint.url}</h1>
                <code className="text-xs text-gray-400 dark:text-gh-dim font-mono">{endpoint.url}</code>
              </div>
              {latest && <UptimeBadge status={latest.status} />}
            </div>

            {/* Stats */}
            <div className="grid grid-cols-3 gap-3">
              {stats.map(s => (
                <div key={s.label} className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border p-4 text-center">
                  <div className={`text-2xl font-bold font-mono ${s.color}`}>{s.value}</div>
                  <div className="text-xs text-gray-400 dark:text-gh-dim mt-1 uppercase tracking-wider">{s.label}</div>
                </div>
              ))}
            </div>

            {/* Charts */}
            <div className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border p-4">
              <div className="flex items-center justify-between mb-3">
                <span className="text-sm font-semibold text-gray-800 dark:text-gh-text">Latency</span>
                <span className="text-xs text-gray-400 dark:text-gh-dim bg-gray-100 dark:bg-gh-subtle rounded-full px-2.5 py-0.5">Last 24h</span>
              </div>
              <LatencyChart data={history} />
            </div>

            {/* Recent Checks */}
            <div className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border overflow-hidden">
              <div className="flex items-center justify-between px-4 py-3 border-b border-gray-100 dark:border-gh-border">
                <span className="text-sm font-semibold text-gray-800 dark:text-gh-text">Recent Checks</span>
                <span className="text-xs text-gray-400 dark:text-gh-dim bg-gray-100 dark:bg-gh-subtle rounded-full px-2.5 py-0.5">{history.length} total</span>
              </div>
              <div className="divide-y divide-gray-50 dark:divide-gh-border">
                {[...history].reverse().slice(0, 20).map((p, i) => (
                  <div key={i} className="grid items-center px-4 py-2.5" style={{ gridTemplateColumns: '130px 100px 1fr' }}>
                    <span className="text-xs text-gray-500 dark:text-gh-muted font-mono">{formatTime(p.checkedAt)}</span>
                    <UptimeBadge status={p.status} />
                    {p.latencyMs >= 0
                      ? <span className={`text-xs font-mono font-medium ${latencyCls(p.latencyMs)}`}>{p.latencyMs}ms</span>
                      : <span className="text-xs text-gray-400 dark:text-gh-dim font-mono">—</span>}
                  </div>
                ))}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
